import { defineRuntimePlanner } from '@nmtjs/neem'

import { record } from '../../../../../shared/support/_events.ts'

export default defineRuntimePlanner((ctx) => {
  record({ event: 'bare-package-planner', name: ctx.name, mode: ctx.mode })

  return {
    workers: [{ label: 'bare-package-worker' }],
    options: { fixture: 'bare-package-entry' },
  }
})
